                if !args.is_empty() {
                    let mut operands = Vec::<u8>::new();
                    Self::write_reg(&mut operands, args[0].0);
                    self.ctx.emit(Instruction::FfiExtended {
                        sub_op: 0x73, // TimeSleepNanos
                        operands,
                    });
                }
